it = iter(sys.stdin.read().split())
s = next(it)
unique_chars = {}
res = 0
for i in range(len(s)):
    for j in range(i, len(s)):
        for c in s[i:j+1]:
            unique_chars[c] = 1
        res += len(unique_chars) * (j - i + 1)
        unique_chars.clear()
