solutions.cpp:
#include <bits/stdc++.h>
using namespace std;
int main(){
    string s;
    cin >> s;
    int res = 0;
    for(int i = 0; i < s.size(); i++){
        unordered_map<char, int> unique_chars;
        for(int j = i; j < s.size(); j++){
            unique_chars[s[j]] = 1;
            res += unique_chars.size() * (j - i + 1);
        }
    }
    cout << res << endl;
}
